/// Parameters for converting a random-explorer config into a concolic config.
/// Fields that don't exist on `explorer::ExploreConfig` are provided here.
pub struct ConcolicParams {
    /// Z3 solver timeout in milliseconds per query. None means no limit.
    pub solver_timeout_ms: Option<u64>,
    /// Per-function exploration wall-clock timeout override. If None, inherits
    /// from the explorer config.
    pub timeout_explore: Option<Duration>,
}

impl ExploreConfig {
    /// Build a concolic `ExploreConfig` from the random explorer config plus
    /// concolic-specific parameters. Centralizes the field mapping so the CLI
    /// doesn't manually translate between the two models.
    pub fn from_explorer(
        explorer: &crate::explorer::ExploreConfig,
        params: ConcolicParams,
    ) -> Self {
        let max_iters = explorer.max_iterations as usize;
        Self {
            max_iterations: max_iters,
            max_executions: max_iters * 5,
            plateau_threshold: 20,
            mocks: explorer.mocks.clone(),
            mock_params: explorer.mock_params.clone(),
            solver_timeout_ms: params.solver_timeout_ms,
            timeout_explore: params
                .timeout_explore
                .or(explorer.timeout_explore),
        }
    }
}

