            assert_eq!(concolic.mocks.len(), 1);
            assert_eq!(concolic.mocks[0].symbol, "dep");
            assert_eq!(concolic.mock_params.len(), 1);
            assert_eq!(concolic.mock_params[0].symbol, "dep");
            assert_eq!(concolic.solver_timeout_ms, Some(5000));
            assert_eq!(concolic.timeout_explore, Some(Duration::from_secs(30)));
        }

        #[test]
        fn from_explorer_timeout_override() {
            use crate::explorer;
            use crate::protocol::SetupLevel;

            let explorer_cfg = explorer::ExploreConfig {
                file: "test.ts".into(),
                max_iterations: 5,
                seed: None,
                mocks: vec![],
                mock_params: vec![],
                setup_file: None,
                setup_level: SetupLevel::Function,
                value_sources: vec![],
                capabilities: FrontendCapabilities::default(),
                user_seeds: vec![],
                candidate_inputs: vec![],
                pool_seeds: vec![],
                project_root: None,
                loop_buckets: explorer::LoopBuckets::default(),
                timeout_explore: Some(Duration::from_secs(30)),
            };

            let concolic = ExploreConfig::from_explorer(
                &explorer_cfg,
                ConcolicParams {
                    solver_timeout_ms: None,
                    timeout_explore: Some(Duration::from_secs(10)),
                },
            );

            assert_eq!(concolic.timeout_explore, Some(Duration::from_secs(10)));
        }
    }
}

